function handleCTAClick(){console.log("CTAボタンがクリックされました"),alert("サービス登録ページへ遷移します")}document.querySelectorAll('a[href^="#"]').forEach(t=>{t.addEventListener("click",function(t){t.preventDefault();let e=document.querySelector(this.getAttribute("href"));e&&e.scrollIntoView({behavior:"smooth",block:"start"})})}),document.addEventListener("DOMContentLoaded",function(){console.log("ランディングページが読み込まれました");let t=document.querySelectorAll(".feature-card"),e=new IntersectionObserver(t=>{t.forEach(t=>{t.isIntersecting&&(t.target.style.opacity="0",t.target.style.transform="translateY(20px)",setTimeout(()=>{t.target.style.transition="opacity 0.6s, transform 0.6s",t.target.style.opacity="1",t.target.style.transform="translateY(0)"},100),e.unobserve(t.target))})},{threshold:.1});t.forEach(t=>{e.observe(t)})});